/// Registry for parsing KDF RPC error responses into typed exceptions.
///
/// This class provides automatic conversion of error responses to typed
/// [MmRpcException] subclasses based on the `error_type` field.
abstract final class KdfErrorRegistry {
  KdfErrorRegistry._();

  /// Attempts to parse a JSON error response into a typed [MmRpcException].
  ///
  /// Returns `null` if the error type is not recognized or if the JSON
  /// does not contain an `error_type` field.
  ///
  /// [rpcMethodHint] disambiguates types in [_ambiguousErrorTypes] that share
  /// the same `error_type` string across RPC namespaces (e.g. withdraw vs
  /// delegation `NotSufficientBalance`).
  static MmRpcException? tryParse(
    JsonMap json, {
    String? rpcMethodHint,
  }) {
    final errorType = json['error_type'] as String?;
    if (errorType == null) return null;

    final errorData = json['error_data'];
    final message = json['error'] as String? ?? json['message'] as String?;
    final path = json['error_path'] as String?;
    final trace = json['error_trace'] as String?;

    final withdrawScoped = _tryParseWithdrawScopedAmbiguousType(
      errorType: errorType,
      errorData: errorData,
      rpcMethodHint: rpcMethodHint,
      message: message,
      path: path,
      trace: trace,
    );
    if (withdrawScoped != null) return withdrawScoped;

    if (_ambiguousErrorTypes.contains(errorType)) return null;

    final parser = _errorParsers[errorType];
    if (parser == null) return null;

    try {
      return parser(errorData, message, path, trace);
    } catch (_) {
      // Malformed or unexpected error_data shape — fall back to null so
      // callers can degrade gracefully to GeneralErrorResponse.
      return null;
    }
  }

  static MmRpcException? _tryParseWithdrawScopedAmbiguousType({
    required String errorType,
    required dynamic errorData,
    String? rpcMethodHint,
    String? message,
    String? path,
    String? trace,
  }) {
    if (rpcMethodHint == null || !_isWithdrawRelatedRpcMethod(rpcMethodHint)) {
      return null;
    }
    if (errorType != 'NotSufficientBalance') return null;
    try {
      final w = WithdrawErrorNotSufficientBalance.fromJson(errorData);
      return WithdrawErrorNotSufficientBalanceException(
        coin: w.coin,
        available: w.available,
        required: w.required,
        message: message,
        path: path,
        trace: trace,
      );
    } catch (_) {
      return null;
    }
  }

  static bool _isWithdrawRelatedRpcMethod(String method) {
    return method == 'withdraw' ||
        method == 'task::withdraw::init' ||
        method == 'task::withdraw::status' ||
        method == 'task::withdraw::cancel';
  }

  /// Checks if the given error type string is a known KDF error type.
  static bool isKnownErrorType(String errorType) {
    return _errorParsers.containsKey(errorType);
  }

  /// Returns all known error type strings.
  static Iterable<String> get knownErrorTypes => _errorParsers.keys;

  /// Error types emitted by multiple RPC namespaces.
  ///
  /// Excluded from automatic typed parsing because `error_type` alone
  /// is not enough to disambiguate them.
  static const Set<String> _ambiguousErrorTypes = {
    'AmountTooLow',
    'AtLeastOneNodeRequired',
    'CoinConfigNotFound',
    'CoinCreationError',
    'CoinIsActivatedNotWithHDWallet',
    'CoinIsAlreadyActivated',
    'CoinIsNotFound',
    'CoinIsWalletOnly',
    'CoinNotFound',
    'CoinNotSupported',
    'CoinProtocolParseError',
    'ConnectToNodeError',
    'CouldNotFetchBalance',
    'CouldNotGetBalance',
    'CouldNotGetBlockCount',
    'CustomTokenError',
    'DbError',
    'EnableError',
    'ErrorDerivingAddress',
    'FailedScripthashSubscription',
    'FailedSpawningBalanceEvents',
    'GetEthAddressError',
    'GetNftInfoError',
    'HardwareWalletsAreNotSupportedYet',
    'HwContextNotInitialized',
    'HwError',
    'IOError',
    'Internal',
    'InternalError',
    'InvalidAddress',
    'InvalidBip44Chain',
    'InvalidConfiguration',
    'InvalidParam',
    'InvalidPath',
    'InvalidPayload',
    'InvalidPlatformConfiguration',
    'InvalidRequest',
    'InvalidResponse',
    'LegacyError',
    'MetamaskError',
    'MyAddressError',
    'MyRecentSwapsError',
    'NftProtocolNotSupported',
    'NoSuchChannel',
    'NoSuchCoin',
    'NoSuchTask',
    'NotFound',
    'NotSufficientBalance',
    'NotSufficientBaseCoinBalance',
    'NumConversError',
    'P2PError',
    'PlatformCoinIsNotActivated',
    'PrefixNotFound',
    'PrivKeyPolicyNotAllowed',
    'ProtectFromSpamError',
